#include <stdio.h>
#include <stdlib.h>

int main() {
    FILE *f = fopen("data.txt", "r");
    if (!f) {
        printf("File missing\n");
        return 1;
    }
    char buffer[256];
    while (fgets(buffer, sizeof(buffer), f)) {
        printf("%s", buffer);
    }
    fclose(f);
    return 0;
}

#include <stdio.h>

int main() {
    int numbers[] = {1, 2, 3, 4, 5};
    int size = sizeof(numbers) / sizeof(numbers[0]);
    int squared[5];

    for (int i = 0; i < size; i++) {
        squared[i] = numbers[i] * numbers[i];
    }
    return 0;
}
